import { useEffect, useRef, useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { api, setSignupComplete } from "../api";
import { DISPOSABLE_EMAIL_ERROR, isDisposableEmail } from "../utils/emailValidation";
import "../styles/auth.css";

const RESEND_WINDOW_SECONDS = 120;

export default function Signup() {
  const navigate = useNavigate();
  const [fullName, setFullName] = useState("");
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [mobileNumber, setMobileNumber] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [emailOtpCode, setEmailOtpCode] = useState("");
  const [mobileOtpCode, setMobileOtpCode] = useState("");
  const [pendingEmail, setPendingEmail] = useState("");
  const [pendingMobile, setPendingMobile] = useState("");
  const [emailVerified, setEmailVerified] = useState(false);
  const [mobileVerified, setMobileVerified] = useState(false);
  const [otpStep, setOtpStep] = useState(false);
  const [emailOtpDigits, setEmailOtpDigits] = useState(["", "", "", ""]);
  const [mobileOtpDigits, setMobileOtpDigits] = useState(["", "", "", ""]);
  const [emailResendSeconds, setEmailResendSeconds] = useState(0);
  const [mobileResendSeconds, setMobileResendSeconds] = useState(0);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);
  const emailOtpRefs = useRef([]);
  const mobileOtpRefs = useRef([]);

  const normalizeOtp = (value) => value.replace(/\D/g, "").slice(0, 4);

  const syncEmailOtp = (value) => {
    const cleaned = normalizeOtp(value);
    setEmailOtpCode(cleaned);
    setEmailOtpDigits([0, 1, 2, 3].map((idx) => cleaned[idx] || ""));
  };

  const syncMobileOtp = (value) => {
    const cleaned = normalizeOtp(value);
    setMobileOtpCode(cleaned);
    setMobileOtpDigits([0, 1, 2, 3].map((idx) => cleaned[idx] || ""));
  };

  const handleOtpDigitChange = (type, index, value) => {
    const nextChar = value.replace(/\D/g, "").slice(-1);
    const isEmail = type === "email";
    const digits = isEmail ? [...emailOtpDigits] : [...mobileOtpDigits];
    digits[index] = nextChar;

    const joined = digits.join("");
    if (isEmail) {
      setEmailOtpDigits(digits);
      setEmailOtpCode(joined);
      if (nextChar && index < 3) {
        emailOtpRefs.current[index + 1]?.focus();
      }
    } else {
      setMobileOtpDigits(digits);
      setMobileOtpCode(joined);
      if (nextChar && index < 3) {
        mobileOtpRefs.current[index + 1]?.focus();
      }
    }
  };

  const handleOtpKeyDown = (type, index, event) => {
    if (event.key !== "Backspace") {
      return;
    }
    const isEmail = type === "email";
    const digits = isEmail ? emailOtpDigits : mobileOtpDigits;
    if (digits[index] || index === 0) {
      return;
    }
    if (isEmail) {
      emailOtpRefs.current[index - 1]?.focus();
    } else {
      mobileOtpRefs.current[index - 1]?.focus();
    }
  };

  useEffect(() => {
    if (!otpStep) {
      return;
    }
    setEmailResendSeconds(RESEND_WINDOW_SECONDS);
    setMobileResendSeconds(0);
    emailOtpRefs.current[0]?.focus();
  }, [otpStep]);

  useEffect(() => {
    const timer = setInterval(() => {
      setEmailResendSeconds((prev) => (prev > 0 ? prev - 1 : 0));
      setMobileResendSeconds((prev) => (prev > 0 ? prev - 1 : 0));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const resendEmailOtp = async () => {
    const targetEmail = pendingEmail || email;
    if (!targetEmail) {
      setError("Email is required to resend OTP.");
      return;
    }

    try {
      setError("");
      setMessage("");
      setLoading(true);
      await api.post("/auth/send-email-otp/", { email: targetEmail });
      setLoading(false);
      setEmailResendSeconds(RESEND_WINDOW_SECONDS);
      setMessage("A new OTP has been sent to your email.");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Unable to resend email OTP.");
    }
  };

  const resendMobileOtp = async () => {
    const targetEmail = pendingEmail || email;
    const targetMobile = pendingMobile || mobileNumber;
    if (!targetEmail || !targetMobile) {
      setError("Email and mobile number are required to resend mobile OTP.");
      return;
    }

    try {
      setError("");
      setMessage("");
      setLoading(true);
      await api.post("/auth/send-mobile-otp/", {
        email: targetEmail,
        mobile_number: targetMobile,
      });
      setLoading(false);
      setMobileResendSeconds(RESEND_WINDOW_SECONDS);
      setMessage("A new OTP has been sent to your mobile number.");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Unable to resend mobile OTP.");
    }
  };

  const handleSignup = async (e) => {
    e.preventDefault();

    if (password !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    if (password.length < 6) {
      setError("Password must be at least 6 characters.");
      return;
    }

    if (isDisposableEmail(email)) {
      setError(DISPOSABLE_EMAIL_ERROR);
      return;
    }

    try {
      setError("");
      setMessage("");
      setLoading(true);
      const res = await api.post("/auth/signup/", {
        full_name: fullName,
        username,
        email,
        mobile_number: mobileNumber,
        password,
        confirm_password: confirmPassword,
      });
      setSignupComplete();
      setLoading(false);
      setPendingEmail(email);
      setPendingMobile(mobileNumber);
      setOtpStep(true);
      setEmailVerified(false);
      setMobileVerified(false);
      syncEmailOtp("");
      syncMobileOtp("");
      setMessage(res.data?.detail || "Signup successful. Check your inbox for the OTP.");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Signup failed. Please try again.");
    }
  };

  const handleVerifyEmail = async (e) => {
    e.preventDefault();

    try {
      setError("");
      setMessage("");
      setLoading(true);
      await api.post("/auth/verify-email-otp/", {
        email: pendingEmail || email,
        code: emailOtpCode,
      });
      setLoading(false);
      setEmailVerified(true);
      setMessage("Email verified successfully.");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Unable to verify email OTP.");
    }
  };

  const handleVerifyMobile = async (e) => {
    e.preventDefault();

    try {
      setError("");
      setMessage("");
      setLoading(true);
      await api.post("/auth/verify-mobile-otp/", {
        email: pendingEmail || email,
        mobile_number: pendingMobile || mobileNumber,
        code: mobileOtpCode,
      });
      setLoading(false);
      setMobileVerified(true);
      setMessage("Mobile number verified successfully.");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Unable to verify mobile OTP.");
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <div className="auth-header">
          <h1>Create Account</h1>
          <p>Create your account with a real email, then sign in to continue.</p>
        </div>

        {!otpStep ? (
          <form onSubmit={handleSignup} className="auth-form">
            <div className="form-group">
              <label htmlFor="fullName">Full Name</label>
              <input
                id="fullName"
                type="text"
                placeholder="Enter your full name"
                value={fullName}
                onChange={(e) => setFullName(e.target.value)}
                required
              />
              <div className="input-focus"></div>
            </div>

          <div className="form-group">
            <label htmlFor="username">Username</label>
            <input
              id="username"
              type="text"
              placeholder="Choose a username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              placeholder="Enter your email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

            <div className="form-group">
              <label htmlFor="mobileNumber">Mobile Number</label>
              <input
                id="mobileNumber"
                type="tel"
                placeholder="Example: +919876543210"
                value={mobileNumber}
                onChange={(e) => setMobileNumber(e.target.value)}
                required
              />
              <div className="input-focus"></div>
            </div>

          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              type="password"
                placeholder="At least 8 chars, with upper/lower/number/symbol"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          <div className="form-group">
            <label htmlFor="confirmPassword">Confirm Password</label>
            <input
              id="confirmPassword"
              type="password"
              placeholder="Confirm your password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          {error && <div className="error-box">{error}</div>}
          {message && <div className="success-message">{message}</div>}

          <button type="submit" className="btn-signup" disabled={loading}>
            {loading ? "Creating Account..." : "Sign Up"}
          </button>
          </form>
        ) : (
          <form onSubmit={handleVerifyEmail} className="auth-form">
            <div className="form-group">
              <label htmlFor="verificationCode">Email OTP</label>
              <div className="otp-box-row">
                {[0, 1, 2, 3].map((index) => (
                  <input
                    key={`email-otp-${index}`}
                    ref={(el) => {
                      emailOtpRefs.current[index] = el;
                    }}
                    className="otp-box-input"
                    type="text"
                    inputMode="numeric"
                    maxLength={1}
                    value={emailOtpDigits[index]}
                    onChange={(e) => handleOtpDigitChange("email", index, e.target.value)}
                    onKeyDown={(e) => handleOtpKeyDown("email", index, e)}
                  />
                ))}
              </div>
              <input
                id="verificationCode"
                type="text"
                placeholder="Paste full 4-digit email OTP"
                value={emailOtpCode}
                onChange={(e) => syncEmailOtp(e.target.value)}
                required
                style={{ marginTop: 10 }}
              />
              <div className="input-focus"></div>
              <p>In local setup, OTP appears in the backend terminal (console email backend).</p>
              {emailVerified && <p style={{ color: "#1aa260", marginTop: 8 }}>Email verified.</p>}
            </div>

            {error && <div className="error-box">{error}</div>}
            {message && <div className="success-message">{message}</div>}

            <button type="submit" className="btn-signup" disabled={loading}>
              {loading ? "Verifying..." : "Verify Email"}
            </button>

            <button
              type="button"
              className="btn-login"
              style={{ marginTop: 12 }}
              onClick={resendEmailOtp}
              disabled={loading || emailResendSeconds > 0}
            >
              {emailResendSeconds > 0 ? `Resend OTP in ${emailResendSeconds}s` : "Resend OTP"}
            </button>
            {emailResendSeconds > 0 && (
              <div className="otp-timer-wrap" aria-hidden="true">
                <div
                  className={`otp-timer-fill ${emailResendSeconds <= 20 ? "is-warning" : ""}`}
                  style={{ width: `${((RESEND_WINDOW_SECONDS - emailResendSeconds) / RESEND_WINDOW_SECONDS) * 100}%` }}
                ></div>
              </div>
            )}

            <div className="form-group" style={{ marginTop: 16 }}>
              <label htmlFor="mobileVerificationCode">Mobile OTP</label>
              <div className="otp-box-row">
                {[0, 1, 2, 3].map((index) => (
                  <input
                    key={`mobile-otp-${index}`}
                    ref={(el) => {
                      mobileOtpRefs.current[index] = el;
                    }}
                    className="otp-box-input"
                    type="text"
                    inputMode="numeric"
                    maxLength={1}
                    value={mobileOtpDigits[index]}
                    onChange={(e) => handleOtpDigitChange("mobile", index, e.target.value)}
                    onKeyDown={(e) => handleOtpKeyDown("mobile", index, e)}
                  />
                ))}
              </div>
              <input
                id="mobileVerificationCode"
                type="text"
                placeholder="Paste full 4-digit mobile OTP"
                value={mobileOtpCode}
                onChange={(e) => syncMobileOtp(e.target.value)}
                style={{ marginTop: 10 }}
              />
              <div className="input-focus"></div>
              {mobileVerified && <p style={{ color: "#1aa260", marginTop: 8 }}>Mobile verified.</p>}
            </div>

            <button
              type="button"
              className="btn-signup"
              style={{ marginTop: 12 }}
              onClick={handleVerifyMobile}
              disabled={loading}
            >
              {loading ? "Verifying..." : "Verify Mobile"}
            </button>

            <button
              type="button"
              className="btn-login"
              style={{ marginTop: 12 }}
              onClick={resendMobileOtp}
              disabled={loading || mobileResendSeconds > 0}
            >
              {mobileResendSeconds > 0
                ? `Resend Mobile OTP in ${mobileResendSeconds}s`
                : "Send / Resend Mobile OTP"}
            </button>
            {mobileResendSeconds > 0 && (
              <div className="otp-timer-wrap" aria-hidden="true">
                <div
                  className={`otp-timer-fill ${mobileResendSeconds <= 20 ? "is-warning" : ""}`}
                  style={{ width: `${((RESEND_WINDOW_SECONDS - mobileResendSeconds) / RESEND_WINDOW_SECONDS) * 100}%` }}
                ></div>
              </div>
            )}

            <button
              type="button"
              className="btn-login"
              style={{ marginTop: 12 }}
              onClick={() => navigate("/login")}
              disabled={!emailVerified || !mobileVerified}
            >
              {emailVerified && mobileVerified ? "Go to Sign In" : "Verify Email and Mobile First"}
            </button>
          </form>
        )}

        <div className="auth-footer">
          <p>Temporary/disposable emails are not allowed.</p>
          <p>Already have an account? <Link to="/login" className="auth-link">Sign In</Link></p>
        </div>
      </div>
    </div>
  );
}
